import "../quiz_question.dart";

const _subject = "Biology";

QuizQuestion _q(String text, List<String> options, String correct, String explanation) {
  return QuizQuestion(
    subject: _subject,
    text: text,
    options: options,
    correctIndex: options.indexOf(correct),
    explanation: explanation,
  );
}

/// WAEC/NECO Biology — Section 2: Form and Function. Covers nutrition,
/// transport, respiration, excretion, support and movement, and
/// coordination and control.
